for (const item of $input.all()) {
  try {
    // 1. Parse the string inside "output" into a real JSON object
    const parsedOutput = JSON.parse(item.json.output);

    // 2. Extract the icebreaker text
    let cleanText = parsedOutput.icebreaker;

    // 3. Clean up the literal "\n" characters so they become actual line breaks
    item.json.icebreaker = cleanText.replace(/\\n/g, '\n');

    // Optional: Remove the old messy 'output' field to keep the table clean
    delete item.json.output;

  } catch (error) {
    // If an item fails, we label it so you can find it in the sheet
    item.json.icebreaker = "Error parsing AI output";
  }
}

return $input.all();

